#include <stdio.h>
#include <stdlib.h>

// Structure to represent a priority queue node
typedef struct Node {
    int data;
    struct Node* next;
} Node;

// Structure to represent a priority queue
typedef struct PriorityQueue {
    Node* head;
} PriorityQueue;

// Function to create a new priority queue node
Node* createNode(int data) {
    Node* newNode = (Node*) malloc(sizeof(Node));
    newNode->data = data;
    newNode->next = NULL;
    return newNode;
}

// Function to insert a new node into the priority queue
void insert(PriorityQueue* queue, int data) {
    Node* newNode = createNode(data);
    if (queue->head == NULL || queue->head->data < newNode->data) {
        newNode->next = queue->head;
        queue->head = newNode;
    } else {
        Node* current = queue->head;
        while (current->next != NULL && current->next->data > newNode->data) {
            current = current->next;
        }
        newNode->next = current->next;
        current->next = newNode;
    }
}

// Function to remove and return the maximum element from the priority queue
int removeMax(PriorityQueue* queue) {
    if (queue->head == NULL) {
        return -1;
    }
    int max = queue->head->data;
    Node* temp = queue->head;
    queue->head = queue->head->next;
    free(temp);
    return max;
}

int main() {
    int N, M;
    scanf("%d %d", &N, &M);
    PriorityQueue queue;
    queue.head = NULL;
    for (int i = 0; i < N; i++) {
        int num;
        scanf("%d", &num);
        insert(&queue, num);
    }
    for (int i = 0; i < M; i++) {
        int Q;
        scanf("%d", &Q);
        for (int j = 0; j < Q - 1; j++) {
            int max = removeMax(&queue);
            if (max / 2 > 0) {
                insert(&queue, max / 2);
            }
        }
        int max = removeMax(&queue);
        printf("%d\n", max);
    }
    return 0;
}

