function readline() {
    return input[idx++];
}

function solve() {
    let [N, M] = readline().split(' ').map(Number);
    let queue = [];
    let nums = readline().split(' ').map(Number);
    for (let num of nums) {
        queue.push(num);
    }
    queue.sort((a, b) => b - a);
    for (let i = 0; i < M; i++) {
        let Q = Number(readline());
        for (let j = 0; j < Q - 1; j++) {
            let max = queue.shift();
            if (Math.floor(max / 2) > 0) {
                queue.push(Math.floor(max / 2));
                queue.sort((a, b) => b - a);
            }
        }
        let max = queue.shift();
        console.log(max);
    }
}

solve();

